import React, { useEffect, useRef, useState } from 'react';
import axios from 'axios';
import SockJS from 'sockjs-client';
import { Client } from '@stomp/stompjs';

export default function Dashboard() {
  const [incidents, setIncidents] = useState([]);
  const [loading, setLoading] = useState(true);
  const [connectionStatus, setConnectionStatus] = useState('connecting');
  const [filterStatus, setFilterStatus] = useState('all');
  const clientRef = useRef(null);

  useEffect(() => {
    fetchIncidents();
    clientRef.current = connectWebSocket();

    return () => {
      if (clientRef.current) {
        try {
          clientRef.current.deactivate();
        } catch (e) {}
      }
    };
  }, []);

  const connectWebSocket = () => {
    try {
      const client = new Client({
        webSocketFactory: () => new SockJS('/ws'),
        debug: () => {},
        onConnect: () => {
          setConnectionStatus('connected');
          client.subscribe('/topic/incidents', (message) => {
            const data = JSON.parse(message.body);
            setIncidents(prev => {
              const filtered = prev.filter(i => i.id !== data.id);
              return [data, ...filtered];
            });
          });
        },
        onDisconnect: () => setConnectionStatus('disconnected')
      });
      client.activate();
      return client;
    } catch (err) {
      setConnectionStatus('error');
      return null;
    }
  };

  const fetchIncidents = async () => {
    try {
      setLoading(true);
      const res = await axios.get('/api/incidents');
      setIncidents(res.data.sort((a, b) => new Date(b.createdAt) - new Date(a.createdAt)));
    } catch (err) {
      console.error('Error fetching incidents:', err);
    } finally {
      setLoading(false);
    }
  };

  const updateIncidentStatus = async (id, status) => {
    try {
      await axios.put(`/api/incidents/${id}/status?status=${status}`);
    } catch (err) {
      console.error('Error updating incident:', err);
    }
  };

  const getSeverityClass = (severity) => {
    const classes = {
      LOW: 'severity-low',
      MEDIUM: 'severity-medium',
      HIGH: 'severity-high'
    };
    return classes[severity] || '';
  };

  const getStatusBadge = (status) => {
    const badges = {
      REPORTED: 'badge-reported',
      IN_PROGRESS: 'badge-in-progress',
      RESOLVED: 'badge-resolved'
    };
    return badges[status] || '';
  };

  const filteredIncidents = filterStatus === 'all'
    ? incidents
    : incidents.filter(i => i.status === filterStatus);

  const reportedCount = incidents.filter(i => i.status === 'REPORTED').length;
  const progressCount = incidents.filter(i => i.status === 'IN_PROGRESS').length;
  const resolvedCount = incidents.filter(i => i.status === 'RESOLVED').length;

  return (
    <div className="dashboard-container">
      <div className="card dashboard-card">
        <div className="dashboard-header">
          <div>
            <h2>Authority Dashboard</h2>
            <p className="subtitle">Real-time incident monitoring and coordination</p>
          </div>
          <div className="connection-status">
            <span className={`status-indicator ${connectionStatus}`}></span>
            <span>{connectionStatus === 'connected' ? 'Live' : 'Connecting...'}</span>
          </div>
        </div>

        <div className="dashboard-stats">
          <div className="stat-card">
            <span className="stat-label">Total Incidents</span>
            <strong>{incidents.length}</strong>
          </div>
          <div className="stat-card stat-reported">
            <span className="stat-label">Reported</span>
            <strong>{reportedCount}</strong>
          </div>
          <div className="stat-card stat-progress">
            <span className="stat-label">In Progress</span>
            <strong>{progressCount}</strong>
          </div>
          <div className="stat-card stat-resolved">
            <span className="stat-label">Resolved</span>
            <strong>{resolvedCount}</strong>
          </div>
        </div>

        <div className="dashboard-controls">
          <div className="filters">
            <label>Filter by Status:</label>
            <div className="filter-buttons">
              <button
                className={`filter-btn ${filterStatus === 'all' ? 'active' : ''}`}
                onClick={() => setFilterStatus('all')}
              >
                All ({incidents.length})
              </button>
              <button
                className={`filter-btn ${filterStatus === 'REPORTED' ? 'active' : ''}`}
                onClick={() => setFilterStatus('REPORTED')}
              >
                Reported ({incidents.filter(i => i.status === 'REPORTED').length})
              </button>
              <button
                className={`filter-btn ${filterStatus === 'IN_PROGRESS' ? 'active' : ''}`}
                onClick={() => setFilterStatus('IN_PROGRESS')}
              >
                In Progress ({incidents.filter(i => i.status === 'IN_PROGRESS').length})
              </button>
              <button
                className={`filter-btn ${filterStatus === 'RESOLVED' ? 'active' : ''}`}
                onClick={() => setFilterStatus('RESOLVED')}
              >
                Resolved ({incidents.filter(i => i.status === 'RESOLVED').length})
              </button>
            </div>
          </div>
        </div>

        {loading ? (
          <div className="loading">Loading incidents...</div>
        ) : filteredIncidents.length === 0 ? (
          <div className="no-incidents">No incidents to display</div>
        ) : (
          <div className="incidents-list">
            {filteredIncidents.map(incident => (
              <div key={incident.id} className="incident-item">
                <div className="incident-header">
                  <div className="incident-type-badge">
                    <strong>{incident.type}</strong>
                  </div>
                  <div className={`severity-badge ${getSeverityClass(incident.severity)}`}>
                    {incident.severity}
                  </div>
                  <div className={`status-badge ${getStatusBadge(incident.status)}`}>
                    {incident.status.replace('_', ' ')}
                  </div>
                </div>

                <div className="incident-details">
                  <div className="detail-item">
                    <span className="label">Description:</span>
                    <span className="value">{incident.description}</span>
                  </div>
                  <div className="detail-row">
                    <div className="detail-item">
                      <span className="label">Location:</span>
                      <span className="value">{incident.latitude}, {incident.longitude}</span>
                    </div>
                    <div className="detail-item">
                      <span className="label">Reporter:</span>
                      <span className="value">{incident.reporterName}</span>
                    </div>
                  </div>
                  <div className="detail-row">
                    <div className="detail-item">
                      <span className="label">Contact:</span>
                      <span className="value">{incident.contact}</span>
                    </div>
                    <div className="detail-item">
                      <span className="label">Time:</span>
                      <span className="value">{new Date(incident.createdAt).toLocaleString()}</span>
                    </div>
                  </div>
                </div>

                <div className="incident-actions">
                  {incident.status === 'REPORTED' && (
                    <button
                      className="btn btn-action btn-assign"
                      onClick={() => updateIncidentStatus(incident.id, 'IN_PROGRESS')}
                    >
                      Assign Team
                    </button>
                  )}
                  {incident.status === 'IN_PROGRESS' && (
                    <button
                      className="btn btn-action btn-resolve"
                      onClick={() => updateIncidentStatus(incident.id, 'RESOLVED')}
                    >
                      Mark Resolved
                    </button>
                  )}
                  {incident.status === 'RESOLVED' && (
                    <div className="resolved-badge">Completed</div>
                  )}
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}
