import React, { useState } from 'react';
import IncidentForm from './components/IncidentForm';
import Dashboard from './components/Dashboard';

export default function App() {
  const [currentView, setCurrentView] = useState('report');

  return (
    <div className="app">
      <header className="app-header">
        <div className="header-content">
          <div className="logo-section">
            <div className="app-mark">CDRN</div>
            <div className="app-description">
              <h2>Community Disaster Response Network</h2>
              <p>Real-time coordination for emergency management and incident response</p>
            </div>
          </div>
          <nav className="main-nav">
            <button
              className={`nav-btn ${currentView === 'report' ? 'active' : ''}`}
              onClick={() => setCurrentView('report')}
            >
              <span className="icon">📍</span>
              Report Incident
            </button>
            <button
              className={`nav-btn ${currentView === 'dashboard' ? 'active' : ''}`}
              onClick={() => setCurrentView('dashboard')}
            >
              <span className="icon">📊</span>
              Authority Dashboard
            </button>
          </nav>
        </div>
      </header>

      <main className="app-main">
        <div className="view-container">
          <section className="hero-panel">
            <div className="hero-copy">
              <span className="hero-kicker">Fast response. Clear coordination. Live updates.</span>
              <h2>
                One place to report an incident, dispatch a team, and close the loop.
              </h2>
              <p>
                Citizens can report emergencies in seconds. Authorities see them instantly, assign teams, and mark them resolved as the situation changes.
              </p>
              <div className="hero-points">
                <div className="hero-point">
                  <strong>Live</strong>
                  <span>WebSocket updates</span>
                </div>
                <div className="hero-point">
                  <strong>Simple</strong>
                  <span>One form, one dashboard</span>
                </div>
                <div className="hero-point">
                  <strong>Clear</strong>
                  <span>Status from reported to resolved</span>
                </div>
              </div>
            </div>
            <div className="hero-visual">
              <div className="hero-card card-glow">
                <span className="hero-label">Current Mode</span>
                <h3>{currentView === 'report' ? 'Citizen Reporting' : 'Authority Command Center'}</h3>
                <p>
                  {currentView === 'report'
                    ? 'Capture critical details with location and severity in one flow.'
                    : 'Monitor incidents, assign responders, and track resolution in real time.'}
                </p>
              </div>
            </div>
          </section>

          <div className="view-wrapper fade-in">
            {currentView === 'report' && <IncidentForm />}
            {currentView === 'dashboard' && <Dashboard />}
          </div>
        </div>
      </main>

      <footer className="app-footer">
        <p>&copy; 2026 Community Disaster Response Network. Empowering communities to respond faster.</p>
      </footer>
    </div>
  );
}
