import React, { useState } from 'react';
import axios from 'axios';

export default function IncidentForm() {
  const [form, setForm] = useState({
    type: 'Flood',
    description: '',
    latitude: '',
    longitude: '',
    severity: 'HIGH',
    reporterName: '',
    contact: ''
  });
  const [loading, setLoading] = useState(false);
  const [message, setMessage] = useState({ type: '', text: '' });

  const handleChange = (e) => {
    const { name, value } = e.target;
    setForm(prev => ({ ...prev, [name]: value }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setMessage({ type: '', text: '' });

    if (!form.reporterName || !form.latitude || !form.longitude || !form.description) {
      setMessage({ type: 'error', text: 'Please fill all required fields' });
      setLoading(false);
      return;
    }

    try {
      await axios.post('/api/incidents', {
        type: form.type,
        description: form.description,
        latitude: parseFloat(form.latitude),
        longitude: parseFloat(form.longitude),
        severity: form.severity,
        reporterName: form.reporterName,
        contact: form.contact
      });
      setMessage({ type: 'success', text: 'Incident reported successfully! Authorities notified.' });
      setForm({
        type: 'Flood',
        description: '',
        latitude: '',
        longitude: '',
        severity: 'HIGH',
        reporterName: '',
        contact: ''
      });
      setTimeout(() => setMessage({ type: '', text: '' }), 5000);
    } catch (err) {
      setMessage({ type: 'error', text: 'Error reporting incident. Please try again.' });
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="card form-card">
      <div className="card-header">
        <h2>Report Incident / SOS Alert</h2>
        <p className="subtitle">Provide accurate details so the authority dashboard can dispatch a team immediately.</p>
      </div>

      <div className="form-tip">
        Include the location and a short description. The report will appear instantly in the authority dashboard.
      </div>

      <form onSubmit={handleSubmit} className="incident-form">
        <div className="form-group">
          <label htmlFor="type">Incident Type *</label>
          <select
            id="type"
            name="type"
            value={form.type}
            onChange={handleChange}
            required
          >
            <option value="Flood">Flood</option>
            <option value="Fire">Fire</option>
            <option value="Earthquake">Earthquake</option>
            <option value="Blocked Road">Blocked Road</option>
            <option value="Injury">Injury / Medical Emergency</option>
            <option value="Missing Person">Missing Person</option>
            <option value="Other">Other</option>
          </select>
        </div>

        <div className="form-group">
          <label htmlFor="description">Description *</label>
          <textarea
            id="description"
            name="description"
            value={form.description}
            onChange={handleChange}
            placeholder="Describe what you see (e.g., water level, number of people affected, injuries)"
            rows="4"
            required
          />
        </div>

        <div className="form-row">
          <div className="form-group">
            <label htmlFor="latitude">Latitude *</label>
            <input
              id="latitude"
              type="number"
              name="latitude"
              step="0.0001"
              value={form.latitude}
              onChange={handleChange}
              placeholder="e.g., 12.9716"
              required
            />
          </div>
          <div className="form-group">
            <label htmlFor="longitude">Longitude *</label>
            <input
              id="longitude"
              type="number"
              name="longitude"
              step="0.0001"
              value={form.longitude}
              onChange={handleChange}
              placeholder="e.g., 77.5946"
              required
            />
          </div>
        </div>

        <div className="form-group">
          <label htmlFor="severity">Severity Level *</label>
          <select
            id="severity"
            name="severity"
            value={form.severity}
            onChange={handleChange}
            required
          >
            <option value="LOW">Low</option>
            <option value="MEDIUM">Medium</option>
            <option value="HIGH">High</option>
          </select>
        </div>

        <div className="form-group">
          <label htmlFor="reporterName">Your Name *</label>
          <input
            id="reporterName"
            type="text"
            name="reporterName"
            value={form.reporterName}
            onChange={handleChange}
            placeholder="Full name"
            required
          />
        </div>

        <div className="form-group">
          <label htmlFor="contact">Contact Number *</label>
          <input
            id="contact"
            type="tel"
            name="contact"
            value={form.contact}
            onChange={handleChange}
            placeholder="e.g., +919876543210"
            required
          />
        </div>

        <div className="form-actions">
          <button type="submit" disabled={loading} className="btn btn-primary">
            {loading ? 'Sending...' : 'Send SOS Alert'}
          </button>
        </div>
      </form>

      {message.text && (
        <div className={`alert alert-${message.type}`}>
          {message.type === 'success' && 'Delivered '}
          {message.type === 'error' && 'Attention '}
          {message.text}
        </div>
      )}
    </div>
  );
}
